package com.fastfood.controller;

import com.fastfood.dto.ApiResponse;
import com.fastfood.dto.response.KitchenFoodPendingResponse;
import com.fastfood.dto.response.KitchenTableOrderResponse;
import com.fastfood.service.IKitchenService;
import lombok.RequiredArgsConstructor;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/v1/kitchen")
@RequiredArgsConstructor
public class KitchenController {

    private final IKitchenService kitchenService;

    @GetMapping("/orders")
    public ApiResponse<List<KitchenTableOrderResponse>> getPendingOrdersByTable() {
        return ApiResponse.<List<KitchenTableOrderResponse>>builder()
                .code(200)
                .message("Lấy danh sách đơn hàng nhà bếp thành công")
                .data(kitchenService.getPendingOrdersByTable())
                .build();
    }

    @GetMapping("/foods/remaining")
    public ApiResponse<List<KitchenFoodPendingResponse>> getRemainingFoodSummary() {
        return ApiResponse.<List<KitchenFoodPendingResponse>>builder()
                .code(200)
                .message("Lấy danh sách món còn lại thành công")
                .data(kitchenService.getRemainingFoodSummary())
                .build();
    }

    @PostMapping("/orders/items/{orderDetailId}/served")
    public ApiResponse<Void> markOrderItemServed(@PathVariable Long orderDetailId) {
        kitchenService.markOrderItemServed(orderDetailId);
        return ApiResponse.<Void>builder()
                .code(200)
                .message("Đã cập nhật món sang trạng thái hoàn thành")
                .build();
    }
}

package com.fastfood.dto.response;

import lombok.Data;

@Data
public class KitchenFoodPendingResponse {
    private String foodId;
    private String foodName;
    private String imageUrlFood;
    private Integer remainingQuantity;
}

package com.fastfood.dto.response;

import lombok.Data;

@Data
public class KitchenOrderItemResponse {
    private Long orderDetailId;
    private String orderId;
    private String foodId;
    private String foodName;
    private String imageUrlFood;
    private Integer quantity;
}

package com.fastfood.dto.response;

import lombok.Data;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Data
public class KitchenTableOrderResponse {
    private String tableNumber;
    private LocalDateTime firstOrderTime;
    private long elapsedMinutes;
    private List<KitchenOrderItemResponse> items = new ArrayList<>();
}

package com.fastfood.repository;

import com.fastfood.entity.catalog.Food;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

@Repository
public interface FoodRepository extends JpaRepository<Food , String> {
    // Hàm này để hỗ trợ việc tự động sinh mã
    @Query("SELECT MAX(f.idFood) FROM Food f")
    String findMaxidFood();
}

package com.fastfood.repository;

import com.fastfood.entity.catalog.Food;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface FoodRepository extends JpaRepository<Food , String> {
    // Hàm này để hỗ trợ việc tự động sinh mã
    @Query("SELECT MAX(f.idFood) FROM Food f")
    String findMaxidFood();

    @Query("SELECT DISTINCT f FROM Food f " +
            "LEFT JOIN FETCH f.foodIngredients fi " +
            "LEFT JOIN FETCH fi.ingredient")
    List<Food> findAllWithIngredients();
}

package com.fastfood.repository;

import com.fastfood.entity.transaction.OrderDetail;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface OrderDetailRepository extends JpaRepository<OrderDetail, Long> {

    @Query("SELECT od.food.idFood, od.food.foodName, od.food.imageUrlFood, SUM(od.quantity) " +
            "FROM OrderDetail od " +
            "WHERE od.order.status = 'PENDING' AND od.status = 'PENDING' " +
            "GROUP BY od.food.idFood, od.food.foodName, od.food.imageUrlFood " +
            "ORDER BY SUM(od.quantity) DESC")
    List<Object[]> findPendingFoodQuantities();
}

package com.fastfood.repository;

import com.fastfood.entity.transaction.Order;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;
import java.util.List;

@Repository
public interface OrderRepository extends JpaRepository<Order, String> {

    @Query("SELECT MAX(o.idOrder) FROM Order o")
    String findMaxIdOrder();

    // Tìm các đơn hàng chưa phục vụ xong để hiển thị trạng thái bàn trên UI
    List<Order> findByStatus(String status);

    // Tìm đơn hàng đang hoạt động của một bàn cụ thể
    @Query("SELECT o FROM Order o WHERE o.tableNumber = ?1 AND o.status = 'PENDING'")
    Order findActiveOrderByTable(String tableNumber);
}

package com.fastfood.repository;

import com.fastfood.entity.transaction.Order;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface OrderRepository extends JpaRepository<Order, String> {

    @Query("SELECT MAX(o.idOrder) FROM Order o")
    String findMaxIdOrder();

    // Tìm các đơn hàng chưa phục vụ xong để hiển thị trạng thái bàn trên UI
    List<Order> findByStatus(String status);
    
    // Tìm đơn hàng đang hoạt động của một bàn cụ thể
    @Query("SELECT o FROM Order o WHERE o.tableNumber = ?1 AND o.status = 'PENDING'")
    Order findActiveOrderByTable(String tableNumber);

    @Query("SELECT DISTINCT o FROM Order o " +
            "LEFT JOIN FETCH o.orderDetails od " +
            "LEFT JOIN FETCH od.food " +
            "WHERE o.status = 'PENDING' " +
            "ORDER BY o.orderTime ASC")
    List<Order> findPendingOrdersWithDetails();
}

package com.fastfood.service;

import com.fastfood.dto.response.KitchenFoodPendingResponse;
import com.fastfood.dto.response.KitchenTableOrderResponse;

import java.util.List;

public interface IKitchenService {
    List<KitchenTableOrderResponse> getPendingOrdersByTable();
    List<KitchenFoodPendingResponse> getRemainingFoodSummary();
    void markOrderItemServed(Long orderDetailId);
}

package com.fastfood.service.impl;

import com.fastfood.dto.response.KitchenFoodPendingResponse;
import com.fastfood.dto.response.KitchenOrderItemResponse;
import com.fastfood.dto.response.KitchenTableOrderResponse;
import com.fastfood.entity.catalog.Food;
import com.fastfood.entity.catalog.FoodIngredient;
import com.fastfood.entity.transaction.Order;
import com.fastfood.entity.transaction.OrderDetail;
import com.fastfood.repository.FoodRepository;
import com.fastfood.repository.OrderDetailRepository;
import com.fastfood.repository.OrderRepository;
import com.fastfood.service.IKitchenService;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.Duration;
import java.time.LocalDateTime;
import java.util.Comparator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

@Service
@RequiredArgsConstructor
public class KitchenServiceImpl implements IKitchenService {

    private final OrderRepository orderRepository;
    private final OrderDetailRepository orderDetailRepository;
    private final FoodRepository foodRepository;

    @Override
    @Transactional(readOnly = true)
    public List<KitchenTableOrderResponse> getPendingOrdersByTable() {
        List<Order> pendingOrders = orderRepository.findPendingOrdersWithDetails();
        Map<String, KitchenTableOrderResponse> tableMap = new LinkedHashMap<>();

        for (Order order : pendingOrders) {
            KitchenTableOrderResponse tableResponse = tableMap.computeIfAbsent(order.getTableNumber(), tableNumber -> {
                KitchenTableOrderResponse response = new KitchenTableOrderResponse();
                response.setTableNumber(tableNumber);
                response.setFirstOrderTime(order.getOrderTime());
                return response;
            });

            if (order.getOrderTime() != null &&
                    (tableResponse.getFirstOrderTime() == null || order.getOrderTime().isBefore(tableResponse.getFirstOrderTime()))) {
                tableResponse.setFirstOrderTime(order.getOrderTime());
            }

            if (order.getOrderDetails() == null) {
                continue;
            }

            for (OrderDetail detail : order.getOrderDetails()) {
                if (!"PENDING".equalsIgnoreCase(detail.getStatus()) || detail.getFood() == null) {
                    continue;
                }

                KitchenOrderItemResponse itemResponse = new KitchenOrderItemResponse();
                itemResponse.setOrderDetailId(detail.getId());
                itemResponse.setOrderId(order.getIdOrder());
                itemResponse.setFoodId(detail.getFood().getIdFood());
                itemResponse.setFoodName(detail.getFood().getFoodName());
                itemResponse.setImageUrlFood(detail.getFood().getImageUrlFood());
                itemResponse.setQuantity(detail.getQuantity());
                tableResponse.getItems().add(itemResponse);
            }
        }

        LocalDateTime now = LocalDateTime.now();

        return tableMap.values().stream()
                .filter(table -> !table.getItems().isEmpty())
                .peek(table -> {
                    if (table.getFirstOrderTime() == null) {
                        table.setElapsedMinutes(0);
                        return;
                    }
                    long elapsed = Duration.between(table.getFirstOrderTime(), now).toMinutes();
                    table.setElapsedMinutes(Math.max(elapsed, 0));
                })
                .sorted(Comparator.comparing(KitchenTableOrderResponse::getFirstOrderTime, Comparator.nullsLast(Comparator.naturalOrder())))
                .toList();
    }

    @Override
    @Transactional(readOnly = true)
    public List<KitchenFoodPendingResponse> getRemainingFoodSummary() {
        return foodRepository.findAllWithIngredients().stream()
                .map(this::toRemainingFoodResponse)
                .filter(item -> item.getRemainingQuantity() > 0)
                .sorted(Comparator.comparing(KitchenFoodPendingResponse::getRemainingQuantity).reversed())
                .toList();
    }

    private KitchenFoodPendingResponse toRemainingFoodResponse(Food food) {
        KitchenFoodPendingResponse response = new KitchenFoodPendingResponse();
        response.setFoodId(food.getIdFood());
        response.setFoodName(food.getFoodName());
        response.setImageUrlFood(food.getImageUrlFood());
        response.setRemainingQuantity(calculateRemainingQuantity(food));
        return response;
    }

    private int calculateRemainingQuantity(Food food) {
        if (food.getFoodIngredients() == null || food.getFoodIngredients().isEmpty()) {
            return 0;
        }

        int minPortions = Integer.MAX_VALUE;

        for (FoodIngredient recipe : food.getFoodIngredients()) {
            BigDecimal quantityUsed = recipe.getQuantityUsed() == null ? BigDecimal.ZERO : recipe.getQuantityUsed();
            BigDecimal stock = (recipe.getIngredient() == null || recipe.getIngredient().getQuantityStock() == null)
                    ? BigDecimal.ZERO
                    : recipe.getIngredient().getQuantityStock();

            if (quantityUsed.compareTo(BigDecimal.ZERO) <= 0) {
                return 0;
            }

            int portionsByIngredient = stock.divideToIntegralValue(quantityUsed).intValue();
            minPortions = Math.min(minPortions, Math.max(portionsByIngredient, 0));
        }

        return minPortions == Integer.MAX_VALUE ? 0 : minPortions;
    }

    @Override
    @Transactional
    public void markOrderItemServed(Long orderDetailId) {
        OrderDetail orderDetail = orderDetailRepository.findById(orderDetailId)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy chi tiết đơn hàng"));

        if (!"PENDING".equalsIgnoreCase(orderDetail.getStatus())) {
            return;
        }

        orderDetail.setStatus("SERVED");
        orderDetailRepository.save(orderDetail);
    }
}

import React from 'react';
import { BrowserRouter, Routes, Route, Link, Outlet, Navigate } from 'react-router-dom';
import { Layout, Menu, Typography } from 'antd';
import { ShopOutlined, DatabaseOutlined, FireOutlined, UserOutlined } from '@ant-design/icons';

// KÉO CÁC COMPONENT TỪ THƯ MỤC PAGES VÀO
import FoodMenu from './pages/FoodMenu';
import Login from './pages/Login';

// Mấy component này là chỗ để 3 anh em kia code
const KitchenPage = () => <div style={{ padding: 20 }}><h1>Màn hình Bếp (Chờ code...)</h1></div>;
const InventoryPage = () => <div style={{ padding: 20 }}><h1>Màn hình Kho (Chờ code...)</h1></div>;

const { Header, Content, Footer, Sider } = Layout;
const { Title } = Typography;

// TÁCH LAYOUT CÓ MENU RA RIÊNG (ĐỂ TRANG LOGIN KHÔNG BỊ DÍNH VÀO)
const MainLayout = () => {
    return (
        <Layout style={{ minHeight: '100vh' }}>
            {/* CỘT MENU BÊN TRÁI */}
            <Sider theme="dark" breakpoint="lg" collapsedWidth="0">
                <div style={{ height: 32, margin: 16, background: 'rgba(255, 255, 255, 0.2)', borderRadius: 6, display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'white', fontWeight: 'bold' }}>
                    HỆ THỐNG POS
                </div>
                <Menu theme="dark" mode="inline" defaultSelectedKeys={['1']}>
                    <Menu.Item key="1" icon={<ShopOutlined />}>
                        <Link to="/pos">Máy POS (Kiosk)</Link>
                    </Menu.Item>
                    <Menu.Item key="2" icon={<FireOutlined />}>
                        <Link to="/kitchen">Nhà Bếp</Link>
                    </Menu.Item>
                    <Menu.Item key="3" icon={<DatabaseOutlined />}>
                        <Link to="/inventory">Quản lý Kho</Link>
                    </Menu.Item>
                    <Menu.Item key="4" icon={<UserOutlined />}>
                        <Link to="/login">Đăng xuất</Link>
                    </Menu.Item>
                </Menu>
            </Sider>

            {/* KHUNG HIỂN THỊ NỘI DUNG CHÍNH (BÊN PHẢI) */}
            <Layout>
                <Header style={{ padding: 0, background: '#fff', display: 'flex', alignItems: 'center', paddingLeft: 20 }}>
                    <Title level={4} style={{ margin: 0 }}>FastFood Team 4 Dashboard</Title>
                </Header>

                <Content style={{ margin: '24px 16px 0' }}>
                    <div style={{ minHeight: 360, background: '#fff', borderRadius: 8 }}>

                        {/* THẺ OUTLET SẼ TỰ ĐỘNG NHÉT FOODMENU HOẶC INVENTORY VÀO ĐÂY */}
                        <Outlet />

                    </div>
                </Content>

                <Footer style={{ textAlign: 'center' }}>
                    FastFood Team 4 ©{new Date().getFullYear()} - UI designed with Ant Design
                </Footer>
            </Layout>
        </Layout>
    );
};

function App() {
    return (
        <BrowserRouter>
            <Routes>
                {/* 1. TRANG ĐĂNG NHẬP FULL MÀN HÌNH (NẰM NGOÀI LAYOUT) */}
                <Route path="/login" element={<Login />} />

                {/* 2. CÁC TRANG CÓ MENU VÀ HEADER (NẰM TRONG LAYOUT) */}
                <Route element={<MainLayout />}>
                    {/* Mặc định vào Web là nhảy thẳng vào POS */}
                    <Route path="/" element={<Navigate to="/pos" replace />} />
                    <Route path="/pos" element={<FoodMenu />} />
                    <Route path="/kitchen" element={<KitchenPage />} />
                    <Route path="/inventory" element={<InventoryPage />} />
                </Route>
            </Routes>
        </BrowserRouter>
    );
}

export default App;

import React from 'react';
import { BrowserRouter, Routes, Route, Link, Outlet, Navigate, useLocation, useNavigate } from 'react-router-dom';
import { Button, Layout, Menu, Typography } from 'antd';
import {
  AppstoreOutlined,
  CreditCardOutlined,
  DashboardOutlined,
  DatabaseOutlined,
  FireOutlined,
  LogoutOutlined,
  OrderedListOutlined
} from '@ant-design/icons';
import FoodMenu from './pages/FoodMenu';
import KitchenPage from './pages/KitchenPage';
import PaymentPage from './pages/PaymentPage';
import Login from './pages/Login';

const DashboardPage = () => <div style={{ padding: 20 }}><h1>Màn hình Dashboard</h1></div>;
const OrdersPage = () => <div style={{ padding: 20 }}><h1>Màn hình Đơn hàng</h1></div>;
const InventoryPage = () => <div style={{ padding: 20 }}><h1>Màn hình Kho (Chờ code...)</h1></div>;

const { Header, Content, Footer, Sider } = Layout;
const { Title } = Typography;

const normalizeRole = (role) => {
  const normalized = (role || '').trim().toLowerCase();

  if (normalized === 'admin') return 'ADMIN';
  if (normalized === 'thu ngân' || normalized === 'thu ngan') return 'Thu ngân';
  if (normalized === 'bếp' || normalized === 'bep') return 'Bếp';
  if (normalized === 'khách hàng' || normalized === 'khach hang') return 'Khách hàng';

  return role || '';
};

const getStoredRole = () => normalizeRole(localStorage.getItem('userRole'));

const getRoleHomePath = (role) => {
  const normalizedRole = normalizeRole(role);

  if (normalizedRole === 'ADMIN') return '/dashboard';
  if (normalizedRole === 'Thu ngân') return '/payment';
  if (normalizedRole === 'Bếp') return '/kitchen';
  if (normalizedRole === 'Khách hàng') return '/menu';

  return '/login';
};

const isRoleNavigable = (role) => getRoleHomePath(role) !== '/login';

const ProtectedRoute = ({ children, allowedRoles }) => {
  const role = getStoredRole();

  if (!role) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !allowedRoles.map(normalizeRole).includes(role)) {
    return <Navigate to={getRoleHomePath(role)} replace />;
  }

  return children;
};

const HomeRedirect = () => {
  return <Navigate to={getRoleHomePath(getStoredRole())} replace />;
};

const menuItems = [
  { key: 'dashboard', path: '/dashboard', label: 'Dashboard', icon: <DashboardOutlined />, roles: ['ADMIN'] },
  { key: 'orders', path: '/orders', label: 'Đơn hàng', icon: <OrderedListOutlined />, roles: ['ADMIN'] },
  { key: 'menu', path: '/menu', label: 'Menu', icon: <AppstoreOutlined />, roles: ['ADMIN', 'Khách hàng'] },
  { key: 'inventory', path: '/inventory', label: 'Kho', icon: <DatabaseOutlined />, roles: ['ADMIN'] },
  { key: 'kitchen', path: '/kitchen', label: 'Bếp', icon: <FireOutlined />, roles: ['Bếp'] },
  { key: 'payment', path: '/payment', label: 'Thanh Toán', icon: <CreditCardOutlined />, roles: ['Thu ngân'] }
];

const MainLayout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const role = getStoredRole();

  const visibleMenuItems = menuItems.filter((item) => item.roles.map(normalizeRole).includes(role));
  const selectedKey = menuItems.find((item) => item.path === location.pathname)?.key || '';

  const handleLogout = () => {
    localStorage.removeItem('userRole');
    localStorage.removeItem('username');
    localStorage.removeItem('fullName');
    navigate('/login', { replace: true });
  };

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Sider theme="dark" breakpoint="lg" collapsedWidth="0">
        <div style={{ height: 32, margin: 16, background: 'rgba(255, 255, 255, 0.2)', borderRadius: 6, display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'white', fontWeight: 'bold' }}>
          HỆ THỐNG POS
        </div>

        <Menu theme="dark" mode="inline" selectedKeys={[selectedKey]}>
          {visibleMenuItems.map((item) => (
            <Menu.Item key={item.key} icon={item.icon}>
              <Link to={item.path}>{item.label}</Link>
            </Menu.Item>
          ))}
        </Menu>
      </Sider>

      <Layout>
        <Header style={{ background: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 20px' }}>
          <Title level={4} style={{ margin: 0 }}>FastFood Team 4 Dashboard</Title>
          <Button icon={<LogoutOutlined />} onClick={handleLogout}>Đăng xuất</Button>
        </Header>

        <Content style={{ margin: '24px 16px 0' }}>
          <div style={{ minHeight: 360, background: '#fff', borderRadius: 8 }}>
            <Outlet />
          </div>
        </Content>

        <Footer style={{ textAlign: 'center' }}>
          FastFood Team 4 ©{new Date().getFullYear()} - UI designed with Ant Design
        </Footer>
      </Layout>
    </Layout>
  );
};

function App() {
  const role = getStoredRole();
  const roleHomePath = getRoleHomePath(role);

  return (
    <BrowserRouter>
      <Routes>
        <Route
          path="/login"
          element={role && isRoleNavigable(role) ? <Navigate to={roleHomePath} replace /> : <Login />}
        />

        <Route
          element={(
            <ProtectedRoute>
              <MainLayout />
            </ProtectedRoute>
          )}
        >
          <Route path="/" element={<HomeRedirect />} />
          <Route path="/dashboard" element={<ProtectedRoute allowedRoles={['ADMIN']}><DashboardPage /></ProtectedRoute>} />
          <Route path="/orders" element={<ProtectedRoute allowedRoles={['ADMIN']}><OrdersPage /></ProtectedRoute>} />
          <Route path="/menu" element={<ProtectedRoute allowedRoles={['ADMIN', 'Khách hàng']}><FoodMenu /></ProtectedRoute>} />
          <Route path="/pos" element={<Navigate to="/menu" replace />} />
          <Route path="/inventory" element={<ProtectedRoute allowedRoles={['ADMIN']}><InventoryPage /></ProtectedRoute>} />
          <Route path="/kitchen" element={<ProtectedRoute allowedRoles={['Bếp']}><KitchenPage /></ProtectedRoute>} />
          <Route path="/payment" element={<ProtectedRoute allowedRoles={['Thu ngân']}><PaymentPage /></ProtectedRoute>} />
        </Route>

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;

.kitchen-page {
  display: flex;
  gap: 16px;
  min-height: 72vh;
}

.kitchen-sidebar {
  width: 220px;
  background: #d2d2d2;
  border-radius: 20px;
  padding: 18px 14px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.kitchen-logo {
  height: 72px;
  border-radius: 12px;
  background: #f1f1f1;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 36px;
  margin-bottom: 16px;
}

.kitchen-tab-btn {
  border: none;
  background: #8d888a;
  color: #fff;
  text-align: left;
  border-radius: 10px;
  height: 50px;
}

.kitchen-tab-btn.active,
.kitchen-tab-btn:hover {
  background: #595557 !important;
  color: #fff !important;
}

.kitchen-main {
  flex: 1;
  background: #d2d2d2;
  border-radius: 20px;
  overflow: hidden;
}

.kitchen-topbar {
  height: 78px;
  background: #b2b0b1;
  display: flex;
  align-items: center;
  gap: 24px;
  padding: 0 24px;
}

.kitchen-topbar h3 {
  margin: 0;
  min-width: 130px;
  font-size: 34px;
  font-weight: 500;
}

.kitchen-search {
  max-width: 480px;
}

.kitchen-content {
  padding: 18px;
  max-height: calc(72vh - 78px);
  overflow-y: auto;
}

.kitchen-loading {
  min-height: 300px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.table-card {
  background: #c8c8c8;
  border-radius: 22px;
  margin-bottom: 18px;
  overflow: hidden;
}

.table-card-header {
  background: #b2b0b1;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 26px;
  font-size: 34px;
  font-weight: 300;
}

.toggle-btn {
  border: none;
  background: transparent;
  color: #fff;
  font-size: 20px;
  cursor: pointer;
}

.table-card-body {
  padding: 14px;
}

.kitchen-item {
  background: #ededed;
  border: 1px solid #ddd;
  border-radius: 4px;
  display: flex;
  align-items: center;
  gap: 18px;
  padding: 14px;
  margin-bottom: 10px;
}

.item-image {
  width: 96px;
  height: 96px;
  object-fit: cover;
  border-radius: 2px;
  background: #8f8f8f;
}

.item-info {
  flex: 1;
}

.item-title {
  margin: 0;
  font-size: 32px;
}

.item-qty {
  margin: 6px 0 0;
  color: #6c6c6c;
  font-size: 28px;
  font-style: italic;
}

.done-btn {
  font-size: 34px;
  color: #333 !important;
}

.food-list-card {
  background: #c8c8c8;
  border-radius: 22px;
  padding: 14px;
}

@media (max-width: 1400px) {
  .kitchen-page {
    flex-direction: column;
  }

  .kitchen-sidebar {
    width: 100%;
  }

  .table-card-header,
  .item-title,
  .item-qty,
  .kitchen-topbar h3 {
    font-size: 20px;
  }

  .item-image {
    width: 70px;
    height: 70px;
  }
}

import React, { useEffect, useMemo, useState } from 'react';
import { Input, Button, Empty, Spin, message } from 'antd';
import { SearchOutlined, DownOutlined, UpOutlined, MinusSquareOutlined } from '@ant-design/icons';
import apiClient from '../api/apiClient';
import '../css/KitchenPage.css';

const DEFAULT_FOOD_IMAGE = 'https://via.placeholder.com/120x120?text=FOOD';

const formatElapsed = (minutes) => {
  const safeMinutes = Number.isFinite(minutes) ? Math.max(minutes, 0) : 0;
  const hour = String(Math.floor(safeMinutes / 60)).padStart(2, '0');
  const minute = String(safeMinutes % 60).padStart(2, '0');
  return `${hour}h:${minute}m`;
};

const KitchenPage = () => {
  const [activeTab, setActiveTab] = useState('orders');
  const [searchText, setSearchText] = useState('');
  const [tableOrders, setTableOrders] = useState([]);
  const [remainingFoods, setRemainingFoods] = useState([]);
  const [expandedMap, setExpandedMap] = useState({});
  const [loading, setLoading] = useState(true);
  const [servingIds, setServingIds] = useState([]);

  const fetchKitchenData = async () => {
    try {
      setLoading(true);
      const [ordersRes, foodsRes] = await Promise.all([
        apiClient.get('/v1/kitchen/orders'),
        apiClient.get('/v1/kitchen/foods/remaining')
      ]);

      const orders = ordersRes?.data?.data ?? [];
      const foods = foodsRes?.data?.data ?? [];

      setTableOrders(orders);
      setRemainingFoods(foods);
      setExpandedMap((prev) => {
        const next = { ...prev };
        orders.forEach((table) => {
          if (next[table.tableNumber] === undefined) {
            next[table.tableNumber] = true;
          }
        });
        return next;
      });
    } catch (error) {
      console.error(error);
      message.error('Khong tai duoc du lieu nha bep');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchKitchenData();
  }, []);

  const onServeItem = async (orderDetailId) => {
    try {
      setServingIds((prev) => [...prev, orderDetailId]);
      await apiClient.post(`/v1/kitchen/orders/items/${orderDetailId}/served`);
      message.success('Da cap nhat mon da hoan thanh');
      await fetchKitchenData();
    } catch (error) {
      console.error(error);
      const errorMessage = error?.response?.data?.message || 'Cap nhat mon that bai';
      message.error(errorMessage);
    } finally {
      setServingIds((prev) => prev.filter((id) => id !== orderDetailId));
    }
  };

  const filteredTableOrders = useMemo(() => {
    const normalized = searchText.trim().toLowerCase();
    if (!normalized) {
      return tableOrders;
    }

    return tableOrders
      .map((table) => {
        const matchedItems = table.items.filter((item) =>
          item.foodName?.toLowerCase().includes(normalized)
        );
        const matchedTable = table.tableNumber?.toLowerCase().includes(normalized);

        if (matchedTable) {
          return table;
        }

        return { ...table, items: matchedItems };
      })
      .filter((table) => table.items.length > 0 || table.tableNumber?.toLowerCase().includes(normalized));
  }, [searchText, tableOrders]);

  const filteredRemainingFoods = useMemo(() => {
    const normalized = searchText.trim().toLowerCase();
    if (!normalized) {
      return remainingFoods;
    }

    return remainingFoods.filter((food) =>
      food.foodName?.toLowerCase().includes(normalized)
    );
  }, [searchText, remainingFoods]);

  const headerTitle = activeTab === 'orders' ? 'Don hang' : 'Mon an';

  return (
    <div className="kitchen-page">
      <aside className="kitchen-sidebar">
        <div className="kitchen-logo">LOGO</div>

        <Button
          className={`kitchen-tab-btn ${activeTab === 'orders' ? 'active' : ''}`}
          onClick={() => setActiveTab('orders')}
        >
          Don hang
        </Button>
        <Button
          className={`kitchen-tab-btn ${activeTab === 'foods' ? 'active' : ''}`}
          onClick={() => setActiveTab('foods')}
        >
          Danh sach mon
        </Button>
      </aside>

      <section className="kitchen-main">
        <div className="kitchen-topbar">
          <h3>{headerTitle}</h3>
          <Input
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(event) => setSearchText(event.target.value)}
            placeholder="search"
            className="kitchen-search"
          />
        </div>

        <div className="kitchen-content">
          {loading ? (
            <div className="kitchen-loading">
              <Spin size="large" />
            </div>
          ) : activeTab === 'orders' ? (
            filteredTableOrders.length === 0 ? (
              <Empty description="Khong co don hang dang cho" />
            ) : (
              filteredTableOrders.map((table) => {
                const expanded = expandedMap[table.tableNumber] !== false;

                return (
                  <div className="table-card" key={table.tableNumber}>
                    <div className="table-card-header">
                      <span>
                        Ban: {table.tableNumber} - {formatElapsed(table.elapsedMinutes)}
                      </span>
                      <button
                        type="button"
                        className="toggle-btn"
                        onClick={() =>
                          setExpandedMap((prev) => ({
                            ...prev,
                            [table.tableNumber]: !expanded
                          }))
                        }
                      >
                        {expanded ? (
                          <>
                            An bot <UpOutlined />
                          </>
                        ) : (
                          <>
                            Hien them <DownOutlined />
                          </>
                        )}
                      </button>
                    </div>

                    {expanded && (
                      <div className="table-card-body">
                        {table.items.map((item) => (
                          <div className="kitchen-item" key={item.orderDetailId}>
                            <img
                              src={item.imageUrlFood || DEFAULT_FOOD_IMAGE}
                              alt={item.foodName}
                              className="item-image"
                              onError={(event) => {
                                event.currentTarget.src = DEFAULT_FOOD_IMAGE;
                              }}
                            />
                            <div className="item-info">
                              <p className="item-title">{item.foodName}</p>
                              <p className="item-qty">So luong: {item.quantity}</p>
                            </div>
                            <Button
                              type="text"
                              icon={<MinusSquareOutlined />}
                              className="done-btn"
                              onClick={() => onServeItem(item.orderDetailId)}
                              loading={servingIds.includes(item.orderDetailId)}
                            />
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })
            )
          ) : filteredRemainingFoods.length === 0 ? (
            <Empty description="Khong co mon con lai" />
          ) : (
            <div className="food-list-card">
              {filteredRemainingFoods.map((food) => (
                <div className="kitchen-item" key={food.foodId}>
                  <img
                    src={food.imageUrlFood || DEFAULT_FOOD_IMAGE}
                    alt={food.foodName}
                    className="item-image"
                    onError={(event) => {
                      event.currentTarget.src = DEFAULT_FOOD_IMAGE;
                    }}
                  />
                  <div className="item-info">
                    <p className="item-title">{food.foodName}</p>
                    <p className="item-qty">So luong con lai: {food.remainingQuantity}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default KitchenPage;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../api/apiClient.js'; // Đảm bảo đường dẫn này đúng với project của bạn
import './Login.css'; // Import file giao diện vừa tạo ở trên

const Login = () => {
    // 1. Tạo các state để lưu dữ liệu người dùng gõ vào
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();

    // 2. Hàm xử lý khi bấm nút Đăng nhập
    const handleLogin = async (e) => {
        e.preventDefault(); // Chặn việc tự động reload trang của thẻ form
        setError('');
        setLoading(true); // Hiển thị trạng thái đang load

        try {
            // Gửi API lên Spring Boot
            const response = await apiClient.post('/auth/login', { username, password });

            // Lấy vai trò (role) từ Backend trả về
            const userRole = response.data.role;

            // Điều hướng màn hình tùy theo Role
            if (userRole === 'Admin' || userRole === 'Quản lý') {
                navigate('/inventory'); // Quản lý cho vào trang Kho
            } else if (userRole === 'Bếp') {
                navigate('/kitchen');
            } else if (userRole === 'Thu ngân') {
                navigate('/pos');
            } else {
                navigate('/');
            }
        } catch (err) {
            // Nếu Spring Boot trả về lỗi 401 (Sai tài khoản/Mật khẩu)
            setError('Sai tài khoản hoặc mật khẩu!');
        } finally {
            setLoading(false); // Tắt trạng thái load
        }
    };

    // 3. Phần giao diện (JSX)
    return (
        <div className="page-container">
            {/* Thanh bên (Sidebar) màu xám bên trái */}
            <div className="sidebar">
                <div className="logo">LOGO</div>
                <div className="slogan-box">
                    <p className="large-gap">Slogan và 1 số ảnh liên quan</p>
                    <p>ăn nhanh chết sớm</p>
                </div>
            </div>

            {/* Nội dung chính màu trắng bên phải */}
            <div className="main-content">
                <p className="instruction-text">Ảnh nền chủ đề đồ ăn</p>
                <div className="login-card">
                    <h2>Đăng nhập vào hệ thống</h2>

                    {/* Gắn hàm handleLogin vào sự kiện submit của form */}
                    <form onSubmit={handleLogin}>
                        <div className="input-group">
                            <label htmlFor="username">Tài khoản</label>
                            <input
                                type="text"
                                id="username"
                                placeholder="Tên tài khoản"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)} // Lưu chữ khách gõ vào state
                                required
                            />
                        </div>
                        <div className="input-group">
                            <label htmlFor="password">Mật khẩu</label>
                            <input
                                type="password"
                                id="password"
                                placeholder="Nhập mật khẩu"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)} // Lưu pass khách gõ vào state
                                required
                            />
                        </div>

                        {/* Hiện thông báo chữ màu đỏ nếu nhập sai mật khẩu */}
                        {error && <p style={{ color: 'red', textAlign: 'center', marginBottom: '15px' }}>{error}</p>}

                        <button type="submit" className="login-button" disabled={loading}>
                            {loading ? 'Đang xử lý...' : 'Đăng nhập'}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../api/apiClient.js'; // Đảm bảo đường dẫn này đúng với project của bạn
import './Login.css'; // Import file giao diện vừa tạo ở trên

const normalizeRole = (role) => {
    const normalized = (role || '').trim().toLowerCase();

    if (normalized === 'admin') return 'ADMIN';
    if (normalized === 'thu ngân' || normalized === 'thu ngan') return 'Thu ngân';
    if (normalized === 'bếp' || normalized === 'bep') return 'Bếp';
    if (normalized === 'khách hàng' || normalized === 'khach hang') return 'Khách hàng';

    return role || '';
};

const getRoleHomePath = (role) => {
    const normalizedRole = normalizeRole(role);

    if (normalizedRole === 'ADMIN') return '/dashboard';
    if (normalizedRole === 'Thu ngân') return '/payment';
    if (normalizedRole === 'Bếp') return '/kitchen';
    if (normalizedRole === 'Khách hàng') return '/menu';

    return '/login';
};

const isRoleNavigable = (role) => getRoleHomePath(role) !== '/login';

const Login = () => {
    // 1. Tạo các state để lưu dữ liệu người dùng gõ vào
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();

    useEffect(() => {
        const savedRole = localStorage.getItem('userRole');
        if (savedRole && isRoleNavigable(savedRole)) {
            navigate(getRoleHomePath(savedRole), { replace: true });
        }
    }, [navigate]);

    // 2. Hàm xử lý khi bấm nút Đăng nhập
    const handleLogin = async (e) => {
        e.preventDefault(); // Chặn việc tự động reload trang của thẻ form
        setError('');
        setLoading(true); // Hiển thị trạng thái đang load

        try {
            // Gửi API lên Spring Boot
            const response = await apiClient.post('/auth/login', { username, password });

            // Lấy vai trò (role) từ Backend trả về
            const userRole = normalizeRole(response.data.role);

            localStorage.setItem('userRole', userRole);
            localStorage.setItem('username', response.data.username || '');
            localStorage.setItem('fullName', response.data.fullName || '');

            navigate(getRoleHomePath(userRole), { replace: true });
        } catch (err) {
            // Nếu Spring Boot trả về lỗi 401 (Sai tài khoản/Mật khẩu)
            setError(err?.response?.data || 'Sai tài khoản hoặc mật khẩu!');
        } finally {
            setLoading(false); // Tắt trạng thái load
        }
    };

    // 3. Phần giao diện (JSX)
    return (
        <div className="page-container">
            {/* Thanh bên (Sidebar) màu xám bên trái */}
            <div className="sidebar">
                <div className="logo">LOGO</div>
                <div className="slogan-box">
                    <p className="large-gap">Slogan và 1 số ảnh liên quan</p>
                    <p>ăn nhanh chết sớm</p>
                </div>
            </div>

            {/* Nội dung chính màu trắng bên phải */}
            <div className="main-content">
                <p className="instruction-text">Ảnh nền chủ đề đồ ăn</p>
                <div className="login-card">
                    <h2>Đăng nhập vào hệ thống</h2>

                    {/* Gắn hàm handleLogin vào sự kiện submit của form */}
                    <form onSubmit={handleLogin}>
                        <div className="input-group">
                            <label htmlFor="username">Tài khoản</label>
                            <input
                                type="text"
                                id="username"
                                placeholder="Tên tài khoản"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)} // Lưu chữ khách gõ vào state
                                required
                            />
                        </div>
                        <div className="input-group">
                            <label htmlFor="password">Mật khẩu</label>
                            <input
                                type="password"
                                id="password"
                                placeholder="Nhập mật khẩu"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)} // Lưu pass khách gõ vào state
                                required
                            />
                        </div>

                        {/* Hiện thông báo chữ màu đỏ nếu nhập sai mật khẩu */}
                        {error && <p style={{ color: 'red', textAlign: 'center', marginBottom: '15px' }}>{error}</p>}

                        <button type="submit" className="login-button" disabled={loading}>
                            {loading ? 'Đang xử lý...' : 'Đăng nhập'}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;

import React from 'react';

